"use client";

import * as React from "react";
import type { ColumnDef } from "@gunjo/ui";
import {
  Header,
  HeaderBrand,
  HeaderActions,
  StatGroup,
  DataTable,
  Gantt,
  ActionQueue,
  InspectorPanel,
  InspectorSection,
  InspectorField,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  Badge,
  Button,
  Select,
  Separator,
  MetadataList,
  ToggleGroup,
  ToggleGroupItem,
  EmptyState,
  type GanttRow,
  type GanttItem,
  type ActionItem,
} from "@gunjo/ui";

import {
  STATIONS,
  TRAINS,
  WORKINGS,
  ISSUES,
  KIND_META,
  stationByCode,
  type TrainPath,
  type Direction,
} from "./data";
import { TrainDiagram } from "./TrainDiagram";

// ── helpers ────────────────────────────────────────────────
const fmtHM = (min?: number) =>
  min == null ? "—" : `${Math.floor(min / 60)}:${String(min % 60).padStart(2, "0")}`;

// 当日 0:00 起点の「分」を Gantt が解する "YYYY-MM-DDTHH:mm" に変換（基準日は任意）。
const BASE = "2026-06-29";
const minToIso = (min: number) =>
  `${BASE}T${String(Math.floor(min / 60)).padStart(2, "0")}:${String(min % 60).padStart(2, "0")}`;

interface TrainRow {
  no: string;
  kindLabel: string;
  badge: "secondary" | "info" | "success" | "warning";
  origin: string;
  destination: string;
  depTokyo: string;
  arrTachikawa: string;
  workingNo: string;
  train: TrainPath;
}

function toRows(trains: TrainPath[]): TrainRow[] {
  return trains.map((t) => {
    const meta = KIND_META[t.kind];
    const first = t.stops[0];
    const last = t.stops[t.stops.length - 1];
    return {
      no: t.no,
      kindLabel: meta.label,
      badge: meta.badge,
      origin: t.origin,
      destination: t.destination,
      depTokyo: fmtHM(first.dep ?? first.arr),
      arrTachikawa: fmtHM(last.arr ?? last.dep),
      workingNo: t.workingNo,
      train: t,
    };
  });
}

// ── 車両運用（行路）→ Gantt rows/items ──────────────────────
const GANTT_TONE: Record<string, GanttItem["tone"]> = {
  便: "primary",
  折返し: "warning",
  出区: "muted",
  入区: "muted",
};

function buildGantt(): { rows: GanttRow[]; items: GanttItem[] } {
  const rows: GanttRow[] = WORKINGS.map((w) => ({
    id: w.workingNo,
    label: `運用 ${w.workingNo}`,
    sublabel: w.consist,
  }));
  const items: GanttItem[] = WORKINGS.map((w) => ({
    id: w.workingNo,
    rowId: w.workingNo,
    start: minToIso(w.legs[0].start),
    end: minToIso(w.legs[w.legs.length - 1].end),
    label: `運用 ${w.workingNo}`,
    tone: "primary",
    ariaLabel: `運用 ${w.workingNo} ${w.consist}`,
    segments: w.legs.map((l) => ({
      start: minToIso(l.start),
      end: minToIso(l.end),
      tone: GANTT_TONE[l.kind] ?? "default",
      kind: l.kind,
      label: l.trainNo ?? l.kind,
    })),
  }));
  return { rows, items };
}

export default function TimetablePlanningPage() {
  const [direction, setDirection] = React.useState<Direction>("down");
  const [selectedNo, setSelectedNo] = React.useState<string | null>("709T");

  const rows = React.useMemo(() => toRows(TRAINS), []);
  const gantt = React.useMemo(() => buildGantt(), []);
  const selectedTrain = TRAINS.find((t) => t.no === selectedNo) ?? null;

  // ── 列車スジ一覧 columns ──
  const columns = React.useMemo<ColumnDef<TrainRow, unknown>[]>(
    () => [
      {
        accessorKey: "no",
        header: "列車番号",
        cell: ({ row }) => (
          <span className="font-medium tabular-nums">{row.original.no}</span>
        ),
      },
      {
        accessorKey: "kindLabel",
        header: "種別",
        cell: ({ row }) => (
          <Badge variant={row.original.badge}>{row.original.kindLabel}</Badge>
        ),
      },
      { accessorKey: "origin", header: "始発" },
      { accessorKey: "destination", header: "終着" },
      {
        accessorKey: "depTokyo",
        header: "東京 発",
        cell: ({ row }) => <span className="tabular-nums">{row.original.depTokyo}</span>,
      },
      {
        accessorKey: "arrTachikawa",
        header: "立川 着",
        cell: ({ row }) => <span className="tabular-nums">{row.original.arrTachikawa}</span>,
      },
      {
        accessorKey: "workingNo",
        header: "運用",
        cell: ({ row }) => (
          <span className="tabular-nums text-muted-foreground">{row.original.workingNo}</span>
        ),
      },
    ],
    []
  );

  // ── 要対応 / 検証 → ActionQueue items ──
  const issueItems = React.useMemo<ActionItem[]>(
    () =>
      ISSUES.map((iss) => ({
        id: iss.id,
        severity: iss.severity,
        kind: iss.kind,
        title: iss.title,
        detail: iss.detail,
        meta: iss.meta,
        onSelect: iss.relatedTrainNo ? () => setSelectedNo(iss.relatedTrainNo!) : undefined,
        actions: iss.relatedTrainNo ? (
          <Button
            variant="outline"
            size="sm"
            onClick={() => setSelectedNo(iss.relatedTrainNo!)}
          >
            スジを表示
          </Button>
        ) : undefined,
      })),
    []
  );

  const criticalCount = ISSUES.filter((i) => i.severity === "critical").length;

  return (
    <div className="flex min-h-screen flex-col bg-muted/20">
      {/* ── 上部チェイン（線区 / ダイヤ改正 / 上下） ── */}
      <Header className="sticky top-0 z-30">
        <HeaderBrand className="flex-col items-start gap-0.5">
          <div className="flex items-center gap-2">
            <h1 className="text-base font-semibold text-foreground">ダイヤ作成 — 運行図表</h1>
            <Badge variant="info">2026.03 ダイヤ改正</Badge>
          </div>
          <p className="text-xs text-muted-foreground">中央線快速 ／ 東京〜立川 ／ 平日</p>
        </HeaderBrand>

        <HeaderActions className="flex-wrap gap-3">
          <Select aria-label="線区" defaultValue="chuo" className="h-8 w-44">
            <option value="chuo">中央線快速</option>
            <option value="yamanote">山手線</option>
            <option value="tokaido">東海道本線</option>
          </Select>
          <Select aria-label="ダイヤ種別" defaultValue="weekday" className="h-8 w-32">
            <option value="weekday">平日</option>
            <option value="holiday">土休日</option>
          </Select>
          <ToggleGroup
            type="single"
            value={direction}
            onValueChange={(v) => v && setDirection(v as Direction)}
            disallowEmpty
            aria-label="運転方向"
          >
            <ToggleGroupItem value="down">下り</ToggleGroupItem>
            <ToggleGroupItem value="up">上り</ToggleGroupItem>
          </ToggleGroup>
          <Button variant="outline" size="sm">運行図表を出力</Button>
          <Button variant="primary" size="sm">スジを追加</Button>
        </HeaderActions>
      </Header>

      <main className="flex flex-1 flex-col gap-4 p-4">
        {/* ── KPI ストリップ ── */}
        <StatGroup
          cols={{ base: 2, md: 4 }}
          items={[
            { label: "設定本数（当該帯・下り）", value: `${TRAINS.length} 本`, hint: "7:00–8:35" },
            {
              label: "ピーク時隔（新宿〜中野）",
              value: "3:45",
              change: "目標 4:00",
              trend: "down",
              tone: "negative",
              hint: "割れ",
            },
            { label: "表定速度（東京〜立川）", value: "44.7 km/h", change: "前回比 +0.3", trend: "up" },
            {
              label: "競合・検証",
              value: `${ISSUES.length} 件`,
              change: `重大 ${criticalCount}`,
              trend: "down",
              tone: "negative",
              hint: "要対応",
            },
          ]}
        />

        {/* ── 作業エリア：左＝図表＋一覧、右＝詳細 ── */}
        <div className="flex flex-col gap-4 xl:flex-row xl:items-start">
          <div className="flex min-w-0 flex-1 flex-col gap-4">
            {/* 運行図表（手組み） */}
            <section className="rounded-lg border border-border bg-card p-4">
              <div className="mb-3 flex flex-wrap items-center justify-between gap-2">
                <div>
                  <h2 className="text-sm font-semibold text-foreground">運行図表 / ダイヤグラム</h2>
                  <p className="text-xs text-muted-foreground">
                    縦軸＝駅（営業キロ）・横軸＝時刻。各列車は1本の斜線（スジ）。クリック／Enter でスジを選択。
                  </p>
                </div>
                {/* 種別凡例 */}
                <div className="flex flex-wrap items-center gap-x-4 gap-y-1">
                  {Object.values(KIND_META).map((m) => (
                    <span key={m.key} className="inline-flex items-center gap-1.5 text-xs text-muted-foreground">
                      <span
                        aria-hidden
                        className="inline-block h-0.5 w-5 rounded"
                        style={{ background: m.stroke }}
                      />
                      {m.label}
                    </span>
                  ))}
                </div>
              </div>
              <TrainDiagram selectedNo={selectedNo} onSelect={setSelectedNo} />
            </section>

            {/* タブ：列車スジ一覧 / 車両運用 / 要対応 */}
            <Tabs defaultValue="trains" className="bg-card">
              <TabsList className="m-3 mb-0">
                <TabsTrigger value="trains">列車スジ一覧</TabsTrigger>
                <TabsTrigger value="workings">車両運用 / 行路</TabsTrigger>
                <TabsTrigger value="issues">
                  要対応 / 検証
                  {criticalCount > 0 && (
                    <Badge variant="destructive" className="ml-2">
                      {criticalCount}
                    </Badge>
                  )}
                </TabsTrigger>
              </TabsList>

              <TabsContent value="trains">
                <DataTable<TrainRow, unknown>
                  columns={columns}
                  data={rows}
                  pageSize={10}
                  filter={{ columnId: "no", placeholder: "列車番号で絞り込み" }}
                  getRowState={(r) => (r.no === selectedNo ? "selected" : undefined)}
                  onRowClick={(r) => setSelectedNo(r.no)}
                />
              </TabsContent>

              <TabsContent value="workings">
                <p className="mb-3 text-xs text-muted-foreground">
                  運用番号（行路）×時間軸。便→折返し→便の連なりを1本のバーとして表示。折返し時分が不足する運用は警告色。
                </p>
                <Gantt
                  rows={gantt.rows}
                  items={gantt.items}
                  startDate={minToIso(7 * 60)}
                  endDate={minToIso(9 * 60)}
                  dayWidth={1100}
                  rowLabelWidth={150}
                  laneHeight={34}
                  label="車両運用 行路 ガントチャート"
                  onSelectItem={(it) => {
                    const w = WORKINGS.find((x) => x.workingNo === it.id);
                    const firstTrain = w?.legs.find((l) => l.trainNo)?.trainNo;
                    if (firstTrain) setSelectedNo(firstTrain);
                  }}
                />
              </TabsContent>

              <TabsContent value="issues">
                <ActionQueue items={issueItems} />
              </TabsContent>
            </Tabs>
          </div>

          {/* ── 右：選択スジの詳細 ── */}
          <InspectorPanel
            title={selectedTrain ? `列車スジ詳細 — ${selectedTrain.no}` : "列車スジ詳細"}
            className="h-auto w-full shrink-0 rounded-lg border xl:sticky xl:top-[88px] xl:max-h-[calc(100vh-104px)] xl:w-[360px]"
          >
            {selectedTrain ? (
              <SelectedPathDetail train={selectedTrain} />
            ) : (
              <EmptyState
                title="スジ未選択"
                description="運行図表のスジ、または一覧の行を選んでください。"
              />
            )}
          </InspectorPanel>
        </div>
      </main>
    </div>
  );
}

// ── 選択スジの詳細パネル本体 ──────────────────────────────
function SelectedPathDetail({ train }: { train: TrainPath }) {
  const meta = KIND_META[train.kind];

  // 各駅の着発・停車時分・前駅からの運転時分を算出
  const rowsDetail = train.stops.map((st, i) => {
    const station = stationByCode.get(st.code);
    const dwell = st.arr != null && st.dep != null ? st.dep - st.arr : null;
    let run: number | null = null;
    if (i > 0) {
      const prev = train.stops[i - 1];
      const prevDepart = prev.dep ?? prev.arr;
      const thisArrive = st.arr ?? st.dep;
      if (prevDepart != null && thisArrive != null) run = thisArrive - prevDepart;
    }
    return { station: station?.name ?? st.code, st, dwell, run, pass: st.pass };
  });

  return (
    <>
      <InspectorSection title="概要">
        <div className="flex flex-wrap items-center gap-2">
          <Badge variant={meta.badge}>{meta.label}</Badge>
          <span className="text-sm font-medium text-foreground">{train.no}</span>
        </div>
        <MetadataList
          variant="compact"
          items={[
            { label: "区間", value: `${train.origin} → ${train.destination}` },
            { label: "方向", value: train.direction === "down" ? "下り" : "上り" },
            { label: "運用番号", value: train.workingNo },
          ]}
        />
      </InspectorSection>

      <Separator />

      <InspectorSection title="着発時刻 / 運転・停車時分">
        <div className="overflow-hidden rounded-md border border-border">
          <table className="w-full border-collapse text-xs tabular-nums">
            <thead>
              <tr className="border-b border-border bg-muted/40 text-muted-foreground">
                <th className="px-2 py-1.5 text-left font-medium">駅</th>
                <th className="px-2 py-1.5 text-right font-medium">着</th>
                <th className="px-2 py-1.5 text-right font-medium">発</th>
                <th className="px-2 py-1.5 text-right font-medium">運転</th>
                <th className="px-2 py-1.5 text-right font-medium">停車</th>
              </tr>
            </thead>
            <tbody>
              {rowsDetail.map((r, i) => (
                <tr key={i} className="border-b border-border/60 last:border-0">
                  <td className="px-2 py-1.5 text-left font-medium text-foreground">
                    {r.station}
                    {r.pass && <span className="ml-1 text-[10px] text-muted-foreground">通過</span>}
                  </td>
                  <td className="px-2 py-1.5 text-right">{fmtHM(r.st.arr)}</td>
                  <td className="px-2 py-1.5 text-right">{fmtHM(r.st.dep)}</td>
                  <td className="px-2 py-1.5 text-right text-muted-foreground">
                    {r.run != null ? `${r.run}分` : "—"}
                  </td>
                  <td className="px-2 py-1.5 text-right text-muted-foreground">
                    {r.dwell != null ? `${r.dwell}分` : "—"}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </InspectorSection>

      <Separator />

      <InspectorSection title="前後列車との時隔（参考）">
        <MetadataList
          variant="compact"
          items={[
            { label: "先行列車", value: "709T（新宿 7:35 発）" },
            { label: "続行時隔（新宿）", value: "2分00秒", description: "最小 2分30秒 — 不足" },
            { label: "後続列車", value: "713T（新宿 7:50 発）" },
          ]}
        />
      </InspectorSection>
    </>
  );
}

// 中央線快速 平日下り ダイヤ — 立川折返しを含む朝ラッシュ帯の作業用データ。
// すべて手入力の架空ダイヤ（実在ダイヤではない）だが、駅・種別・時分の作法は実態に寄せている。

export type TrainKind = "local" | "rapid" | "special" | "express";

export interface KindMeta {
  /** 種別キー */
  key: TrainKind;
  /** 表示名（種別） */
  label: string;
  /** スジ（線）の色トークン。運行図表・凡例で共通利用。 */
  stroke: string;
  /** DataTable / Badge 用の Badge variant */
  badge: "secondary" | "info" | "success" | "warning";
}

export const KIND_META: Record<TrainKind, KindMeta> = {
  local: { key: "local", label: "各駅停車", stroke: "var(--muted-foreground)", badge: "secondary" },
  rapid: { key: "rapid", label: "快速", stroke: "var(--info-strong, #2563eb)", badge: "info" },
  special: { key: "special", label: "特別快速", stroke: "var(--success-strong, #16a34a)", badge: "success" },
  express: { key: "express", label: "特急", stroke: "var(--destructive-strong, #dc2626)", badge: "warning" },
};

/** 線区の駅。kmPost は東京起点の営業キロ（運行図表の縦軸＝距離スケール）。 */
export interface StationDef {
  code: string;
  name: string;
  kmPost: number;
}

// 中央線快速：東京〜立川（営業キロは実態に近い丸め値）
export const STATIONS: StationDef[] = [
  { code: "TYO", name: "東京", kmPost: 0.0 },
  { code: "OCM", name: "御茶ノ水", kmPost: 2.6 },
  { code: "SJK", name: "新宿", kmPost: 10.3 },
  { code: "NKN", name: "中野", kmPost: 14.7 },
  { code: "MTK", name: "三鷹", kmPost: 24.1 },
  { code: "KKB", name: "国分寺", kmPost: 30.0 },
  { code: "TCK", name: "立川", kmPost: 37.5 },
];

export const stationByCode = new Map(STATIONS.map((s) => [s.code, s]));

/** ある駅での着発（min は当日 0:00 からの分）。始発駅は arr 省略、終着駅は dep 省略。 */
export interface StopTime {
  code: string;
  /** 着時刻（分）。始発は未設定。 */
  arr?: number;
  /** 発時刻（分）。終着は未設定。 */
  dep?: number;
  /** 通過なら true（着発時刻を持たない通過駅は stops に含めない方針だが、通過待ち表現用に保持） */
  pass?: boolean;
}

export type Direction = "down" | "up";

export interface TrainPath {
  /** 列車番号 */
  no: string;
  kind: TrainKind;
  direction: Direction;
  /** 始発駅名 */
  origin: string;
  /** 終着駅名 */
  destination: string;
  /** 運用番号（車両運用＝行路に対応） */
  workingNo: string;
  stops: StopTime[];
}

const hm = (h: number, m: number) => h * 60 + m;

