"use client";

// 運行図表 / ダイヤグラム（時間–距離 / stringline / Marey）。
//
// @gunjo/ui には対応するプリミティブが存在しない（docs/by-use-case 上でも
// 「斜線(列車運行図表/ダイヤグラム/Marey)は未対応」と明記）。Gantt は
// リソース行×水平バーであり、列車スジ（駅=距離軸を斜めに横断する線）を
// 表現できないため、ここは完全に手組み（SVG）。
//
// CLAUDE.md の「可変データのチャートは HTML/CSS/SVG プリミティブで」方針に沿い、
// 固定形状ではなく入力データから線を生成する。アクセシビリティのため各スジを
// <a>/role 付きの focusable な要素にし、キーボードでスジを選べるようにしている。

import * as React from "react";
import {
  STATIONS,
  TRAINS,
  WINDOW,
  KIND_META,
  stationByCode,
  type TrainPath,
} from "./data";

interface TrainDiagramProps {
  selectedNo: string | null;
  onSelect: (no: string) => void;
}

// レイアウト定数（px, SVG ユーザー座標）
const PAD = { top: 28, right: 20, bottom: 8, left: 132 };
const PLOT_W = 940;
const PLOT_H = 360;
const SVG_W = PAD.left + PLOT_W + PAD.right;
const SVG_H = PAD.top + PLOT_H + PAD.bottom;

const KM_MIN = STATIONS[0].kmPost;
const KM_MAX = STATIONS[STATIONS.length - 1].kmPost;

function xForMin(min: number): number {
  const t = (min - WINDOW.start) / (WINDOW.end - WINDOW.start);
  return PAD.left + t * PLOT_W;
}

function yForKm(km: number): number {
  const t = (km - KM_MIN) / (KM_MAX - KM_MIN);
  return PAD.top + t * PLOT_H;
}

function fmtHM(min: number): string {
  const h = Math.floor(min / 60);
  const m = min % 60;
  return `${h}:${String(m).padStart(2, "0")}`;
}

/** 1本のスジ（列車）を着発時刻からポリラインの頂点列に変換。 */
function pointsFor(train: TrainPath): { x: number; y: number; min: number }[] {
  const pts: { x: number; y: number; min: number }[] = [];
  for (const st of train.stops) {
    const station = stationByCode.get(st.code);
    if (!station) continue;
    const y = yForKm(station.kmPost);
    // 着→（停車）→発 で水平のキンクを作る
    if (st.arr != null) pts.push({ x: xForMin(st.arr), y, min: st.arr });
    if (st.dep != null) pts.push({ x: xForMin(st.dep), y, min: st.dep });
  }
  return pts;
}

// 時間軸の目盛（5分・15分）
const timeTicks: number[] = [];
for (let m = WINDOW.start; m <= WINDOW.end; m += 5) timeTicks.push(m);

export function TrainDiagram({ selectedNo, onSelect }: TrainDiagramProps) {
  return (
    <figure className="m-0 w-full overflow-x-auto" aria-label="中央線快速 平日下り 運行図表（時間–距離ダイヤグラム）">
      <svg
        viewBox={`0 0 ${SVG_W} ${SVG_H}`}
        width={SVG_W}
        height={SVG_H}
        role="group"
        aria-roledescription="運行図表"
        className="max-w-none"
        style={{ minWidth: SVG_W }}
      >
        {/* 縦のグリッド（時刻） */}
        {timeTicks.map((m) => {
          const x = xForMin(m);
          const isQuarter = m % 15 === 0;
          return (
            <g key={`t-${m}`}>
              <line
                x1={x}
                y1={PAD.top}
                x2={x}
                y2={PAD.top + PLOT_H}
                stroke="var(--border)"
                strokeWidth={isQuarter ? 1 : 0.5}
                opacity={isQuarter ? 0.9 : 0.45}
              />
              {isQuarter && (
                <text
                  x={x}
                  y={PAD.top - 10}
                  textAnchor="middle"
                  className="fill-muted-foreground"
                  style={{ fontSize: 11, fontVariantNumeric: "tabular-nums" }}
                >
                  {fmtHM(m)}
                </text>
              )}
            </g>
          );
        })}

        {/* 横のグリッド（駅 / 距離）＋ 駅名ラベル（縦軸） */}
        {STATIONS.map((s) => {
          const y = yForKm(s.kmPost);
          return (
            <g key={s.code}>
              <line
                x1={PAD.left}
                y1={y}
                x2={PAD.left + PLOT_W}
                y2={y}
                stroke="var(--border)"
                strokeWidth={1}
                opacity={0.9}
              />
              <text
                x={PAD.left - 12}
                y={y}
                textAnchor="end"
                dominantBaseline="middle"
                className="fill-foreground"
                style={{ fontSize: 12, fontWeight: 500 }}
              >
                {s.name}
              </text>
              <text
                x={PAD.left - 12}
                y={y + 13}
                textAnchor="end"
                dominantBaseline="middle"
                className="fill-muted-foreground"
                style={{ fontSize: 9, fontVariantNumeric: "tabular-nums" }}
              >
                {s.kmPost.toFixed(1)} km
              </text>
            </g>
          );
        })}

        {/* 列車スジ（diagonal lines） */}
        {TRAINS.map((train) => {
          const meta = KIND_META[train.kind];
          const pts = pointsFor(train);
          if (pts.length < 2) return null;
          const d = pts.map((p, i) => `${i === 0 ? "M" : "L"}${p.x},${p.y}`).join(" ");
          const isSel = selectedNo === train.no;
          const start = pts[0];
          const accessibleName = `${train.no} ${meta.label} ${train.origin}発${fmtHM(
            start.min
          )} ${train.destination}行`;
          return (
            <g
              key={train.no}
              role="button"
              tabIndex={0}
              aria-pressed={isSel}
              aria-label={accessibleName}
              className="cursor-pointer outline-none [&:focus-visible_path]:stroke-[3.5] group"
              onClick={() => onSelect(train.no)}
              onKeyDown={(e) => {
                if (e.key === "Enter" || e.key === " ") {
                  e.preventDefault();
                  onSelect(train.no);
                }
              }}
            >
              {/* 当たり判定を広げる透明な太線 */}
              <path d={d} fill="none" stroke="transparent" strokeWidth={12} />
              <path
                d={d}
                fill="none"
                stroke={meta.stroke}
                strokeWidth={isSel ? 3.5 : 1.75}
                strokeDasharray={train.kind === "local" ? "1 0" : undefined}
                strokeLinejoin="round"
                strokeLinecap="round"
                opacity={selectedNo && !isSel ? 0.32 : 1}
                className="transition-[stroke-width,opacity] group-hover:stroke-[3]"
              />
              {/* 各停車点（着発）にノードを置く＝交差・追抜きの読み取り点 */}
              {pts.map((p, i) => (
                <circle
                  key={i}
                  cx={p.x}
                  cy={p.y}
                  r={isSel ? 2.6 : 1.8}
                  fill={meta.stroke}
                  opacity={selectedNo && !isSel ? 0.32 : 1}
                />
              ))}
              {/* 列車番号ラベル（始端） */}
              <text
                x={start.x + 4}
                y={start.y - 5}
                className="fill-foreground"
                style={{ fontSize: 9.5, fontWeight: isSel ? 700 : 500, fontVariantNumeric: "tabular-nums" }}
                opacity={selectedNo && !isSel ? 0.4 : 1}
              >
                {train.no}
              </text>
            </g>
          );
        })}
      </svg>
    </figure>
  );
}
